// RenameModel renames a model by copying its manifest to the destination name
// and removing the source manifest. Layers are shared between manifests and are
// not duplicated or deleted. It returns os.ErrNotExist if the source model does
// not exist and os.ErrExist if the destination model already exists.
func RenameModel(src, dst model.Name) error {
	if !src.IsFullyQualified() {
		return model.Unqualified(src)
	}
	if !dst.IsFullyQualified() {
		return model.Unqualified(dst)
	}

	if src.Filepath() == dst.Filepath() {
		return nil
	}

	manifests, err := manifest.Path()
	if err != nil {
		return err
	}

	srcpath := filepath.Join(manifests, src.Filepath())
	dstpath := filepath.Join(manifests, dst.Filepath())

	if _, err := os.Stat(srcpath); errors.Is(err, os.ErrNotExist) {
		return err
	} else if err != nil {
		return err
	}

	if _, err := os.Stat(dstpath); err == nil {
		return os.ErrExist
	} else if !errors.Is(err, os.ErrNotExist) {
		return err
	}

	if err := os.MkdirAll(filepath.Dir(dstpath), 0o755); err != nil {
		return err
	}

	srcfile, err := os.Open(srcpath)
	if err != nil {
		return err
	}
	defer srcfile.Close()

	dstfile, err := os.Create(dstpath)
	if err != nil {
		return err
	}
	defer dstfile.Close()

	if _, err = io.Copy(dstfile, srcfile); err != nil {
		return err
	}

	m, err := manifest.ParseNamedManifest(src)
	if err != nil {
		return err
	}
	return m.Remove()
}

